```{.r .cell-code}
# Calculate item statistics
item_stats <- itemstats(SAT12)

# Display basic statistics
data.frame(
  Statistic = c("Mean Score", "Standard Deviation", "Cronbach's Alpha", "Number of Items", "Sample Size"),
  Value = c(
    mean(rowSums(SAT12)),
    sd(rowSums(SAT12)),
    psych::alpha(SAT12)$total$raw_alpha,
    ncol(SAT12),
    nrow(SAT12)
  )
) |>
  gt() |>
  tab_header(
    title = md("**Basic Statistics**"),
    subtitle = "Classical Test Theory Analysis"
  ) |>
  fmt_number(columns = Value, decimals = 3) |>
  tab_style(
    style = cell_fill(color = "#E8F4FD"),
    locations = cells_body(rows = Statistic == "Cronbach's Alpha")
  )
```

