### 希少カテゴリの検出（推定の安定性チェック）

::: {.cell}

```{.r .cell-code}
# Identify items with rare categories (< 5%) using the computed proportions
rare_flags <- prop_data |>
  pivot_longer(-Item, names_to = "Category", values_to = "Prop") |>
  group_by(Item) |>
  summarise(
    MinProp = min(Prop, na.rm = TRUE),
    RareAny = any(Prop < 0.05, na.rm = TRUE)
  ) |>
  arrange(MinProp)

rare_flags |>
  filter(RareAny) |>
  head(10) |>
  gt() |>
  tab_header(
    title = md("**Rare Categories Detected**"),
    subtitle = "Items with any category proportion < 5% (Top 10)"
  ) |>
  fmt_percent(columns = MinProp, decimals = 1)
