# 上位ペアの抽出
ldg2_mat <- as.matrix(ldg2)
ldg2_mat[lower.tri(ldg2_mat, diag = TRUE)] <- NA

ldg2_df <- which(!is.na(ldg2_mat), arr.ind = TRUE) |>
  as.data.frame() |>
  mutate(
    Item1 = paste0('Item', row),
    Item2 = paste0('Item', col),
    LDG2 = ldg2_mat[cbind(row, col)]
  ) |>
  arrange(desc(LDG2))

ldg2_df |>
  slice(1:10) |>
  gt() |>
  tab_header(
    title = md("**Local Dependence (Top LDG2 Pairs)**"),
    subtitle = "Large LDG2 indicates possible local dependence"
  ) |>
  fmt_number(columns = LDG2, decimals = 3)
