### 可視化の読み方（実務のコツ）
- IRCCC（カテゴリ特性）: 交差位置＝弁別するθ帯。ピークが右寄りなら高能力者向け、左寄りなら低能力者向け。
- IIC（項目情報）: 山の高さ＝精度、位置＝得意なθ帯。テスト目的と山の位置が合っているかを確認。
- infoSE（テスト情報）: 青い情報曲線の高い部分でSEが低下。対象集団のθ分布と重なるか確認。

### モデル比較（GRM vs GPCM）

::: {.cell}

```{.r .cell-code}
# Fit Generalized Partial Credit Model as alternative (robust)
fit_gpcm <- try(mirt(SAT12, 1, itemtype = 'gpcm', SE = FALSE, verbose = FALSE), silent = TRUE)

# Safe extractors
safe_num <- function(expr) {
  out <- try(expr, silent = TRUE)
  if (inherits(out, 'try-error') || length(out) == 0) NA_real_ else as.numeric(out)
}
ok_gpcm <- !inherits(fit_gpcm, 'try-error')

AIC_grm  <- safe_num(AIC(fit_grm))
AIC_gpcm <- if (ok_gpcm) safe_num(AIC(fit_gpcm)) else NA_real_
BIC_grm  <- safe_num(BIC(fit_grm))
BIC_gpcm <- if (ok_gpcm) safe_num(BIC(fit_gpcm)) else NA_real_
LL_grm   <- safe_num(logLik(fit_grm))
LL_gpcm  <- if (ok_gpcm) safe_num(logLik(fit_gpcm)) else NA_real_

# Add M2 for reference (may fail for some settings)
m2_grm  <- try(M2(fit_grm,  type = 'C2', calcNULL = FALSE), silent = TRUE)
m2_gpcm <- if (ok_gpcm) try(M2(fit_gpcm, type = 'C2', calcNULL = FALSE), silent = TRUE) else NULL

RMSEA_grm  <- if (inherits(m2_grm, 'list'))  m2_grm$RMSEA  else NA_real_
SRMSR_grm  <- if (inherits(m2_grm, 'list'))  m2_grm$SRMSR  else NA_real_
RMSEA_gpcm <- if (!is.null(m2_gpcm) && inherits(m2_gpcm, 'list')) m2_gpcm$RMSEA else NA_real_
SRMSR_gpcm <- if (!is.null(m2_gpcm) && inherits(m2_gpcm, 'list')) m2_gpcm$SRMSR else NA_real_

# Assemble comparison table (ensure equal lengths)
comp <- data.frame(
  Model  = c('GRM', 'GPCM'),
  AIC    = c(AIC_grm,  AIC_gpcm),
  BIC    = c(BIC_grm,  BIC_gpcm),
  logLik = c(LL_grm,   LL_gpcm),
  RMSEA  = c(RMSEA_grm, RMSEA_gpcm),
  SRMSR  = c(SRMSR_grm, SRMSR_gpcm)
)

comp |>
  gt() |>
  tab_header(
    title = md("**Model Comparison: GRM vs GPCM**"),
    subtitle = "Information criteria and fit indices"
  ) |>
  fmt_number(columns = c(AIC, BIC, logLik, RMSEA, SRMSR), decimals = 3)
```

