# Extract factor loadings
mirt_params <- coef(fit_mirt, simplify = TRUE)
loadings_data <- mirt_params$items[, 1:2]

# Display factor loadings
loadings_df <- data.frame(
  Item = paste0("Item", 1:20),
  F1 = round(loadings_data[,1], 3),
  F2 = round(loadings_data[,2], 3),
  Primary_Factor = case_when(
    loadings_data[,1] > 0.5 & loadings_data[,2] < 0.3 ~ "F1",
    loadings_data[,2] > 0.5 & loadings_data[,1] < 0.3 ~ "F2",
    loadings_data[,1] > 0.3 & loadings_data[,2] > 0.3 ~ "Both",
    TRUE ~ "None"
  )
)

loadings_df |>
  gt() |>
  tab_header(
    title = md("**Multidimensional IRT Factor Loadings**"),
    subtitle = "Two-Factor Model Estimates"
  ) |>
  tab_spanner(
    label = "Factor Loadings",
    columns = c(F1, F2)
  ) |>
  data_color(
    columns = c(F1, F2),
    colors = scales::col_numeric(
      palette = c("white", "darkred"),
      domain = c(0, 2)
    )
  ) |>
  tab_style(
    style = cell_fill(color = "#FFE4B5"),
    locations = cells_body(
      columns = Primary_Factor,
      rows = Primary_Factor == "F1"
    )
  ) |>
  tab_style(
    style = cell_fill(color = "#B0E0E6"),
    locations = cells_body(
      columns = Primary_Factor,
      rows = Primary_Factor == "F2"
    )
  ) |>
  tab_style(
    style = cell_fill(color = "#DDA0DD"),
    locations = cells_body(
      columns = Primary_Factor,
      rows = Primary_Factor == "Both"
    )
  )
