# Extract factor variance-covariance matrix
cov_matrix <- mirt_params$cov

# Convert to correlation matrix
if(is.matrix(cov_matrix) && nrow(cov_matrix) == ncol(cov_matrix)) {
  cor_matrix <- cov2cor(cov_matrix)

  # Display factor correlations
  cor_df <- as.data.frame(cor_matrix)
  rownames(cor_df) <- colnames(cor_df) <- c("Factor 1", "Factor 2")

  cor_df |>
    gt(rownames_to_stub = TRUE) |>
    tab_header(
      title = md("**Factor Correlation Matrix**"),
      subtitle = "Estimated Latent Factor Correlations"
    ) |>
    fmt_number(columns = everything(), decimals = 3) |>
    data_color(
      columns = everything(),
      colors = scales::col_numeric(
        palette = c("white", "darkblue"),
        domain = c(-1, 1)
      )
    )
}
