### モデル比較（1因子 vs 2因子）

::: {.cell}

```{.r .cell-code}
# Fit a unidimensional alternative model (robust)
fit_mirt1 <- try(mirt(sim_data, 1, itemtype = '2PL', verbose = FALSE), silent = TRUE)

safe_num <- function(expr) {
  out <- try(expr, silent = TRUE)
  if (inherits(out, 'try-error') || length(out) == 0) NA_real_ else as.numeric(out)
}

ok_1 <- !inherits(fit_mirt1, 'try-error')
ok_2 <- exists('fit_mirt') && !inherits(try(logLik(fit_mirt), silent = TRUE), 'try-error')

AIC_1 <- if (ok_1) safe_num(AIC(fit_mirt1)) else NA_real_
AIC_2 <- if (ok_2) safe_num(AIC(fit_mirt))  else NA_real_
BIC_1 <- if (ok_1) safe_num(BIC(fit_mirt1)) else NA_real_
BIC_2 <- if (ok_2) safe_num(BIC(fit_mirt))  else NA_real_
LL_1  <- if (ok_1) safe_num(logLik(fit_mirt1)) else NA_real_
LL_2  <- if (ok_2) safe_num(logLik(fit_mirt))  else NA_real_

m2_1 <- if (ok_1) try(M2(fit_mirt1, type = 'C2', calcNULL = FALSE), silent = TRUE) else NULL
m2_2 <- if (ok_2) try(M2(fit_mirt,  type = 'C2', calcNULL = FALSE), silent = TRUE) else NULL

RMSEA_1 <- if (!is.null(m2_1) && inherits(m2_1,'list')) m2_1$RMSEA else NA_real_
RMSEA_2 <- if (!is.null(m2_2) && inherits(m2_2,'list')) m2_2$RMSEA else NA_real_
SRMSR_1 <- if (!is.null(m2_1) && inherits(m2_1,'list')) m2_1$SRMSR else NA_real_
SRMSR_2 <- if (!is.null(m2_2) && inherits(m2_2,'list')) m2_2$SRMSR else NA_real_

comp_mirt <- data.frame(
  Model  = c('1-Factor', '2-Factor'),
  AIC    = c(AIC_1, AIC_2),
  BIC    = c(BIC_1, BIC_2),
  logLik = c(LL_1,  LL_2),
  RMSEA  = c(RMSEA_1, RMSEA_2),
  SRMSR  = c(SRMSR_1, SRMSR_2)
)

comp_mirt |>
  gt() |>
  tab_header(
    title = md("**Model Comparison: 1 vs 2 Factors**"),
    subtitle = "Information criteria and fit indices"
  ) |>
  fmt_number(columns = c(AIC, BIC, logLik, RMSEA, SRMSR), decimals = 3)
```

