q3m <- as.matrix(q3_mirt)
q3m[lower.tri(q3m, diag = TRUE)] <- NA

ld_mirt <- which(!is.na(q3m), arr.ind = TRUE) |>
  as.data.frame() |>
  mutate(
    Item1 = paste0('Item', row),
    Item2 = paste0('Item', col),
    Q3 = q3m[cbind(row, col)]
  ) |>
  arrange(desc(Q3))

ld_mirt |>
  slice(1:10) |>
  gt() |>
  tab_header(
    title = md("**Local Dependence (MIRT, Top Q3 Pairs)**"),
    subtitle = "Inspect for stimulus/content overlap"
  ) |>
  fmt_number(columns = Q3, decimals = 3)
