## 可視化

### 因子負荷マップ（MIRT結果）


::: {.cell}

```{.r .cell-code}
mirt_items <- coef(fit_mirt, simplify = TRUE)$items |>
  as.data.frame()

loading_df <- tibble::tibble(
  Item = paste0("Item", seq_len(nrow(mirt_items))),
  F1 = mirt_items[[1]],
  F2 = mirt_items[[2]]
) |>
  mutate(
    Dominant = case_when(
      abs(F1) >= 0.4 & abs(F2) < 0.4 ~ "F1-dominant",
      abs(F2) >= 0.4 & abs(F1) < 0.4 ~ "F2-dominant",
      abs(F1) >= 0.4 & abs(F2) >= 0.4 ~ "Cross-loading",
      TRUE ~ "Weak loading"
    )
  )

ggplot(loading_df, aes(x = F1, y = F2, color = Dominant, label = Item)) +
  geom_hline(yintercept = 0, color = "gray75") +
  geom_vline(xintercept = 0, color = "gray75") +
  geom_point(size = 3) +
  geom_text(size = 3, nudge_y = 0.04, show.legend = FALSE) +
  scale_color_manual(values = c(
    "F1-dominant" = "#1f78b4",
    "F2-dominant" = "#33a02c",
    "Cross-loading" = "#e31a1c",
    "Weak loading" = "#6a3d9a"
  )) +
  labs(
    title = "MIRT Loading Map",
    x = "Discrimination on Factor 1",
    y = "Discrimination on Factor 2",
    color = "Item pattern"
  ) +
  theme_minimal(base_size = 12)
```

